/**
 * User notification preferences model.
 *
 * Controls how and when notifications are delivered to a user across
 * all supported channels (email, SMS, webhook).
 *
 * DESIGN CHANGE (Agent 9):
 * The original model (Session 3) assumed email-only delivery. With the
 * addition of SMS (Session 8) and webhook (Session 6) channels, this model
 * now supports per-channel opt-in/out. Each channel has its own enabled
 * toggle and per-category settings.
 *
 * Backward compatibility:
 * - `EmailNotificationPreferences` is preserved as a type alias
 * - `getDefaultEmailPreferences()` still works as before
 * - Existing code that reads `preferences.email` is unaffected
 * - New `sms` and `webhook` fields are added alongside `email`
 *
 * Channel defaults:
 * - Email: enabled (existing behavior, least-surprising default)
 * - SMS: disabled (opt-in — more intrusive channel, requires phone number)
 * - Webhook: disabled (opt-in — requires endpoint configuration)
 */

import type { NotificationType } from './notification.js';

/**
 * Per-channel notification settings. Each channel shares this shape:
 * a global enabled toggle plus per-category opt-in/out.
 */
export interface ChannelNotificationPreferences {
  /** Whether this channel is enabled globally for this user. */
  enabled: boolean;
  /** Per-category opt-in/out. If a category is true, that notification type will be sent. */
  categories: Record<NotificationType, boolean>;
}

/**
 * Email-specific notification settings.
 * Preserved as a type alias for backward compatibility with Session 3 code.
 */
export type EmailNotificationPreferences = ChannelNotificationPreferences;

/**
 * SMS-specific notification settings.
 */
export type SmsNotificationPreferences = ChannelNotificationPreferences;

/**
 * Webhook-specific notification settings.
 */
export type WebhookNotificationPreferences = ChannelNotificationPreferences;

/**
 * Full user notification preferences document.
 */
export interface UserNotificationPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  sms: SmsNotificationPreferences;
  webhook: WebhookNotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdateNotificationPreferencesInput {
  email?: {
    enabled?: boolean;
    categories?: Partial<Record<NotificationType, boolean>>;
  };
  sms?: {
    enabled?: boolean;
    categories?: Partial<Record<NotificationType, boolean>>;
  };
  webhook?: {
    enabled?: boolean;
    categories?: Partial<Record<NotificationType, boolean>>;
  };
}

/**
 * Returns default channel preferences with the given enabled state.
 */
function getDefaultChannelPreferences(enabled: boolean): ChannelNotificationPreferences {
  return {
    enabled,
    categories: {
      order_confirmation: true,
      order_status_update: true,
      welcome: true,
      account_updated: true,
    },
  };
}

/**
 * Returns the default email notification preferences (everything enabled).
 */
export function getDefaultEmailPreferences(): EmailNotificationPreferences {
  return getDefaultChannelPreferences(true);
}

/**
 * Returns the default SMS notification preferences (disabled by default — opt-in).
 * Categories are all true so that enabling SMS sends all types immediately.
 */
export function getDefaultSmsPreferences(): SmsNotificationPreferences {
  return getDefaultChannelPreferences(false);
}

/**
 * Returns the default webhook notification preferences (disabled by default — opt-in).
 * Categories are all true so that enabling webhook sends all types immediately.
 */
export function getDefaultWebhookPreferences(): WebhookNotificationPreferences {
  return getDefaultChannelPreferences(false);
}

/**
 * Repository for user notification preferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Serializes per-channel preference objects (email, sms, webhook) as JSON for DB storage.
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { UserNotificationPreferences } from '../models/user-preferences.js';
import { getDefaultSmsPreferences, getDefaultWebhookPreferences } from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserNotificationPreferences> {
  constructor(db: Database) {
    super(db, 'user_notification_preferences');
  }

  protected toDomain(record: DatabaseRecord): UserNotificationPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      email: JSON.parse(record['email'] as string) as UserNotificationPreferences['email'],
      sms: record['sms']
        ? (JSON.parse(record['sms'] as string) as UserNotificationPreferences['sms'])
        : getDefaultSmsPreferences(),
      webhook: record['webhook']
        ? (JSON.parse(record['webhook'] as string) as UserNotificationPreferences['webhook'])
        : getDefaultWebhookPreferences(),
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserNotificationPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      email: JSON.stringify(entity.email),
      sms: JSON.stringify(entity.sms),
      webhook: JSON.stringify(entity.webhook),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserNotificationPreferences | undefined {
    const results = this.findAll((pref) => pref.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — business logic for user notification preferences.
 *
 * Manages CRUD operations for notification preferences and provides
 * a query interface for the NotificationService to check whether a
 * notification should be delivered to a given user on a given channel.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 *
 * Depends on:
 * - PreferencesRepository (data layer) for persistence
 */

import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type {
  UserNotificationPreferences,
  UpdateNotificationPreferencesInput,
  ChannelNotificationPreferences,
} from '../models/user-preferences.js';
import {
  getDefaultEmailPreferences,
  getDefaultSmsPreferences,
  getDefaultWebhookPreferences,
} from '../models/user-preferences.js';
import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(private preferencesRepository: PreferencesRepository) {}

  /**
   * Get preferences for a user. Returns undefined if none exist.
   */
  getPreferences(userId: string): UserNotificationPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating default preferences if none exist.
   */
  getOrCreatePreferences(userId: string): UserNotificationPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    this.logger.info(`Creating default preferences for user ${userId}`);
    const now = new Date();
    const preferences: UserNotificationPreferences = {
      id: generateId(),
      userId,
      email: getDefaultEmailPreferences(),
      sms: getDefaultSmsPreferences(),
      webhook: getDefaultWebhookPreferences(),
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    return preferences;
  }

  /**
   * Update notification preferences for a user.
   * Creates default preferences first if they don't exist, then applies the update.
   */
  updatePreferences(
    userId: string,
    input: UpdateNotificationPreferencesInput,
  ): UserNotificationPreferences {
    const current = this.getOrCreatePreferences(userId);
    this.logger.info(`Updating preferences for user ${userId}`);

    const updatedEmail = this.mergeChannelPreferences(current.email, input.email);
    const updatedSms = this.mergeChannelPreferences(current.sms, input.sms);
    const updatedWebhook = this.mergeChannelPreferences(current.webhook, input.webhook);

    return this.preferencesRepository.update(current.id, {
      email: updatedEmail,
      sms: updatedSms,
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });
  }

  /**
   * Merge partial channel input into existing channel preferences.
   */
  private mergeChannelPreferences(
    current: ChannelNotificationPreferences,
    input?: { enabled?: boolean; categories?: Partial<Record<NotificationType, boolean>> },
  ): ChannelNotificationPreferences {
    if (!input) {
      return { ...current };
    }

    const merged = { ...current };
    if (input.enabled !== undefined) {
      merged.enabled = input.enabled;
    }
    if (input.categories) {
      merged.categories = {
        ...merged.categories,
        ...input.categories,
      };
    }
    return merged;
  }

  /**
   * Check whether a notification should be sent to a user via email.
   *
   * Returns true if:
   * - No preferences exist (default: all enabled)
   * - Email is globally enabled AND the specific category is enabled
   */
  isEmailEnabled(userId: string, type: NotificationType): boolean {
    return this.isChannelEnabled(userId, 'email', type);
  }

  /**
   * Check whether a notification should be sent to a user via SMS.
   *
   * Returns true if:
   * - Preferences exist AND SMS is globally enabled AND the specific category is enabled
   * - Returns false if no preferences exist (SMS defaults to disabled)
   */
  isSmsEnabled(userId: string, type: NotificationType): boolean {
    return this.isChannelEnabled(userId, 'sms', type);
  }

  /**
   * Check whether a notification should be sent to a user via webhook.
   *
   * Returns true if:
   * - Preferences exist AND webhook is globally enabled AND the specific category is enabled
   * - Returns false if no preferences exist (webhook defaults to disabled)
   */
  isWebhookEnabled(userId: string, type: NotificationType): boolean {
    return this.isChannelEnabled(userId, 'webhook', type);
  }

  /**
   * Generic per-channel preference check.
   *
   * When no preferences exist, uses the channel's default:
   * - email: enabled (backward compatible — existing behavior)
   * - sms: disabled (opt-in)
   * - webhook: disabled (opt-in)
   */
  isChannelEnabled(userId: string, channel: NotificationChannel, type: NotificationType): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);
    if (!preferences) {
      // No preferences stored → use channel defaults
      // Email defaults to enabled; SMS and webhook default to disabled
      return channel === 'email';
    }

    const channelPrefs = this.getChannelPreferences(preferences, channel);
    if (!channelPrefs) {
      return false;
    }

    if (!channelPrefs.enabled) {
      return false;
    }

    return channelPrefs.categories[type] !== false;
  }

  /**
   * Get the channel-specific preferences from a user's preferences record.
   */
  private getChannelPreferences(
    preferences: UserNotificationPreferences,
    channel: NotificationChannel,
  ): ChannelNotificationPreferences | undefined {
    switch (channel) {
      case 'email':
        return preferences.email;
      case 'sms':
        return preferences.sms;
      case 'webhook':
        return preferences.webhook;
      default:
        return undefined;
    }
  }
}

/**
 * Notification service — event-driven notification dispatch.
 *
 * ARCHITECTURE:
 * - Subscribes to domain events via EventBus (the ONLY input mechanism).
 * - Maps each event to a NotificationPayload.
 * - Checks user notification preferences per channel before delivery (if PreferencesService is set).
 * - Dispatches payloads through all registered NotificationAdapters.
 * - Stores a record of every notification attempt.
 *
 * CONSTRAINTS:
 * 1. All notifications MUST originate from EventBus events. No direct calls.
 * 2. All delivery MUST go through NotificationAdapter implementations.
 * 3. New event→notification mappings go in registerHandlers().
 * 4. New delivery channels are added by implementing NotificationAdapter and
 *    calling registerAdapter().
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 * - PreferencesService (optional) for checking user notification preferences
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import type { PreferencesService } from './preferences.service.js';
import type { NotificationHistoryService } from './notification-history.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter (for testing). */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: NotificationAdapter[] = [];
  private preferencesService: PreferencesService | null = null;
  private historyService: NotificationHistoryService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Set the preferences service for checking user notification preferences.
   * When set, notifications are suppressed for users who have opted out.
   */
  setPreferencesService(service: PreferencesService): void {
    this.preferencesService = service;
    this.logger.info('Preferences service registered');
  }

  /**
   * Set the notification history service for logging sent notifications.
   * When set, every dispatched notification is persisted to the history log.
   */
  setHistoryService(service: NotificationHistoryService): void {
    this.historyService = service;
    this.logger.info('History service registered');
  }

  /**
   * Register a notification adapter for delivery.
   * Multiple adapters can be registered — each notification is sent through all of them.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter: ${adapter.channel}`);
    this.adapters.push(adapter);
  }

  /**
   * Subscribe to domain events that should trigger notifications.
   * Add new event→notification mappings here.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatch({
      type: 'order_confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
      metadata: { orderId: event.order.id, userId: event.user.id },
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.dispatch({
      type: 'order_status_update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
      metadata: {
        orderId: event.order.id,
        userId: event.order.userId,
        previousStatus: event.previousStatus,
        newStatus: event.newStatus,
      },
    });
  }

  /**
   * Dispatch a notification payload through all registered adapters.
   * Checks user preferences per channel before sending (if PreferencesService is set).
   * If no adapters are registered, stores the notification with channel 'email' as a fallback record.
   */
  private async dispatch(payload: NotificationPayload): Promise<void> {
    const userId = payload.metadata?.['userId'] as string | undefined;

    if (this.adapters.length === 0) {
      // Check preferences before storing the fallback record
      if (userId && this.preferencesService && !this.preferencesService.isChannelEnabled(userId, 'email', payload.type)) {
        this.logger.info(`Notification suppressed for user ${userId}: ${payload.type} (email disabled)`);
        return;
      }
      // No adapters registered — store as in-memory record for backward compatibility
      this.storeNotification(payload, 'email', true);
      return;
    }

    for (const adapter of this.adapters) {
      // Check per-channel preferences
      if (userId && this.preferencesService) {
        if (!this.preferencesService.isChannelEnabled(userId, adapter.channel, payload.type)) {
          this.logger.info(
            `Notification suppressed for user ${userId}: ${payload.type} (${adapter.channel} disabled)`,
          );
          continue;
        }
      }

      const result = await adapter.send(payload);
      this.storeNotification(payload, adapter.channel, result.success, result.error);
    }
  }

  /**
   * Store a notification record.
   */
  private storeNotification(
    payload: NotificationPayload,
    channel: Notification['channel'],
    success: boolean,
    error?: string,
  ): void {
    const notification: Notification = {
      id: generateNotificationId(),
      type: payload.type,
      channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      status: success ? 'sent' : 'failed',
      sentAt: new Date(),
      error,
      metadata: payload.metadata,
    };
    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} [${channel}] to ${payload.recipient}: ${notification.status}`);

    if (this.historyService) {
      this.historyService.log(notification);
    }
  }

  /**
   * Get all notification records.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications filtered by type.
   */
  getNotificationsByType(type: NotificationType): Notification[] {
    return this.notifications.filter((n) => n.type === type);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

