      });
      expect(updated.webhook.enabled).toBe(true);
    });

    it('should enable webhook and disable a category', () => {
      service.getOrCreatePreferences('user-0001');
      const updated = service.updatePreferences('user-0001', {
        webhook: { enabled: true, categories: { account_updated: false } },
      });
      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.categories.account_updated).toBe(false);
      expect(updated.webhook.categories.order_confirmation).toBe(true);
    });
  });

  describe('updatePreferences — multi-channel', () => {
    it('should update email and SMS in one call', () => {
      service.getOrCreatePreferences('user-0001');
      const updated = service.updatePreferences('user-0001', {
        email: { categories: { welcome: false } },
        sms: { enabled: true },
      });
      expect(updated.email.categories.welcome).toBe(false);
      expect(updated.sms.enabled).toBe(true);
      // Webhook unchanged
      expect(updated.webhook.enabled).toBe(false);
    });

    it('should update all three channels in one call', () => {
      service.getOrCreatePreferences('user-0001');
      const updated = service.updatePreferences('user-0001', {
        email: { enabled: false },
        sms: { enabled: true },
        webhook: { enabled: true, categories: { welcome: false } },
      });
      expect(updated.email.enabled).toBe(false);
      expect(updated.sms.enabled).toBe(true);
      expect(updated.webhook.enabled).toBe(true);
      expect(updated.webhook.categories.welcome).toBe(false);
    });
  });

  describe('isEmailEnabled', () => {
    it('should return true when no preferences exist (default)', () => {
      expect(service.isEmailEnabled('user-0001', 'order_confirmation')).toBe(true);
      expect(service.isEmailEnabled('user-0001', 'welcome')).toBe(true);
    });

    it('should return true when all defaults are in place', () => {
      service.getOrCreatePreferences('user-0001');
      expect(service.isEmailEnabled('user-0001', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      service.getOrCreatePreferences('user-0001');
      service.updatePreferences('user-0001', { email: { enabled: false } });
      expect(service.isEmailEnabled('user-0001', 'order_confirmation')).toBe(false);
      expect(service.isEmailEnabled('user-0001', 'order_status_update')).toBe(false);
    });

    it('should return false for a disabled category', () => {
      service.getOrCreatePreferences('user-0001');
      service.updatePreferences('user-0001', {
        email: { categories: { order_status_update: false } },
      });
      expect(service.isEmailEnabled('user-0001', 'order_status_update')).toBe(false);
      expect(service.isEmailEnabled('user-0001', 'order_confirmation')).toBe(true);
    });

    it('should return false when email is disabled even if category is enabled', () => {
      service.getOrCreatePreferences('user-0001');
      service.updatePreferences('user-0001', { email: { enabled: false } });
      // Categories are still all true, but email is globally off
      expect(service.isEmailEnabled('user-0001', 'order_confirmation')).toBe(false);
    });
  });

  describe('isSmsEnabled', () => {
    it('should return false when no preferences exist (SMS defaults to disabled)', () => {
      expect(service.isSmsEnabled('user-0001', 'order_confirmation')).toBe(false);
    });

    it('should return false when preferences exist with SMS default (disabled)', () => {
      service.getOrCreatePreferences('user-0001');
      expect(service.isSmsEnabled('user-0001', 'order_confirmation')).toBe(false);
    });

    it('should return true when SMS is explicitly enabled', () => {
      service.getOrCreatePreferences('user-0001');
      service.updatePreferences('user-0001', { sms: { enabled: true } });
      expect(service.isSmsEnabled('user-0001', 'order_confirmation')).toBe(true);
    });

    it('should return false for a disabled SMS category even when SMS is enabled', () => {
      service.getOrCreatePreferences('user-0001');
      service.updatePreferences('user-0001', {
        sms: { enabled: true, categories: { order_status_update: false } },
      });
      expect(service.isSmsEnabled('user-0001', 'order_status_update')).toBe(false);
      expect(service.isSmsEnabled('user-0001', 'order_confirmation')).toBe(true);
    });
  });

  describe('isWebhookEnabled', () => {
    it('should return false when no preferences exist (webhook defaults to disabled)', () => {
      expect(service.isWebhookEnabled('user-0001', 'order_confirmation')).toBe(false);
    });

    it('should return true when webhook is explicitly enabled', () => {
      service.getOrCreatePreferences('user-0001');
      service.updatePreferences('user-0001', { webhook: { enabled: true } });
      expect(service.isWebhookEnabled('user-0001', 'order_confirmation')).toBe(true);
    });

    it('should return false for a disabled webhook category', () => {
      service.getOrCreatePreferences('user-0001');
      service.updatePreferences('user-0001', {
        webhook: { enabled: true, categories: { welcome: false } },
      });
      expect(service.isWebhookEnabled('user-0001', 'welcome')).toBe(false);
      expect(service.isWebhookEnabled('user-0001', 'order_confirmation')).toBe(true);
    });
  });

  describe('isChannelEnabled', () => {
    it('should delegate to channel-specific defaults when no preferences exist', () => {
      expect(service.isChannelEnabled('user-0001', 'email', 'welcome')).toBe(true);
      expect(service.isChannelEnabled('user-0001', 'sms', 'welcome')).toBe(false);
      expect(service.isChannelEnabled('user-0001', 'webhook', 'welcome')).toBe(false);
    });

    it('should return false for unsupported channels', () => {
      service.getOrCreatePreferences('user-0001');
      expect(service.isChannelEnabled('user-0001', 'in_app', 'welcome')).toBe(false);
    });
  });
});

describe('NotificationService with preferences', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let preferencesService: PreferencesService;
  let preferencesRepo: PreferencesRepository;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationService.setPreferencesService(preferencesService);
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
  });

  const makeOrderCreatedEvent = (userId: string, email: string): OrderCreatedEvent => ({
    type: 'order:created',
    order: {
      id: 'order-1',
      userId,
      items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
      total: 10,
      status: 'pending',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    user: {
      id: userId,
      name: 'Alice',
      email,
      role: 'member',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    timestamp: new Date(),
  });

  const makeStatusChangedEvent = (userId: string): OrderStatusChangedEvent => ({
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId,
      items: [],
      total: 10,
      status: 'confirmed',
      createdAt: new Date(),
      updatedAt: new Date(),
    },
    previousStatus: 'pending',
    newStatus: 'confirmed',
    timestamp: new Date(),
  });

  describe('without adapters (fallback mode)', () => {
    it('should send notification when no preferences are set', async () => {
      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress notification when email is globally disabled', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', { email: { enabled: false } });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should suppress notification for a disabled category', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        email: { categories: { order_confirmation: false } },
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should send notification when category is enabled', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      // Disable a different category
      preferencesService.updatePreferences('user-0001', {
        email: { categories: { welcome: false } },
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress status update notification when that category is disabled', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        email: { categories: { order_status_update: false } },
      });

      await eventBus.emit(makeStatusChangedEvent('user-0001'));
      expect(notificationService.getNotificationCount()).toBe(0);
    });
  });

  describe('with email adapter', () => {
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
    });

    it('should send email when preferences allow it', async () => {
      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress email when globally disabled', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', { email: { enabled: false } });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should suppress email when category is disabled', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        email: { categories: { order_confirmation: false } },
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should not affect notifications for users without preferences', async () => {
      // user-0001 has disabled order confirmations
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        email: { categories: { order_confirmation: false } },
      });

      // user-0002 has no preferences (defaults to enabled)
      await eventBus.emit(makeOrderCreatedEvent('user-0002', 'bob@example.com'));
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(emailAdapter.getSentEmails()[0]?.to).toBe('bob@example.com');
    });
  });

  describe('with SMS adapter', () => {
    let smsAdapter: SmsAdapter;

    beforeEach(() => {
      smsAdapter = new SmsAdapter({ fromNumber: '+15551234567' });
      notificationService.registerAdapter(smsAdapter);
    });

    it('should suppress SMS when user has no preferences (SMS defaults to disabled)', async () => {
      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      // No preferences → SMS defaults to disabled
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should suppress SMS when user has default preferences (SMS disabled)', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });

    it('should send SMS when user has opted in', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', { sms: { enabled: true } });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress SMS for a disabled category even when SMS is enabled', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        sms: { enabled: true, categories: { order_confirmation: false } },
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
    });
  });

  describe('with webhook adapter', () => {
    let webhookAdapter: WebhookAdapter;

    beforeEach(() => {
      webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
      notificationService.registerAdapter(webhookAdapter);
    });

    it('should suppress webhook when user has no preferences (webhook defaults to disabled)', async () => {
      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(webhookAdapter.getDeliveries()).toHaveLength(0);
    });

    it('should send webhook when user has opted in', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', { webhook: { enabled: true } });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(webhookAdapter.getDeliveries()).toHaveLength(1);
    });
  });

  describe('multi-channel dispatch', () => {
    let emailAdapter: EmailAdapter;
    let smsAdapter: SmsAdapter;
    let webhookAdapter: WebhookAdapter;

    beforeEach(() => {
      emailAdapter = new EmailAdapter();
      smsAdapter = new SmsAdapter({ fromNumber: '+15551234567' });
      webhookAdapter = new WebhookAdapter({ url: 'https://hooks.example.com/notify' });
      notificationService.registerAdapter(emailAdapter);
      notificationService.registerAdapter(smsAdapter);
      notificationService.registerAdapter(webhookAdapter);
    });

    it('should send to all enabled channels', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(webhookAdapter.getDeliveries()).toHaveLength(1);
      expect(notificationService.getNotificationCount()).toBe(3);
    });

    it('should only send to email when SMS and webhook are disabled (default)', async () => {
      // Default preferences: email enabled, SMS disabled, webhook disabled
      preferencesService.getOrCreatePreferences('user-0001');

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(emailAdapter.getSentEmails()).toHaveLength(1);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(webhookAdapter.getDeliveries()).toHaveLength(0);
      expect(notificationService.getNotificationCount()).toBe(1);
    });

    it('should suppress all channels when all are disabled', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        email: { enabled: false },
        // SMS and webhook are already disabled by default
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(smsAdapter.getSentMessages()).toHaveLength(0);
      expect(webhookAdapter.getDeliveries()).toHaveLength(0);
      expect(notificationService.getNotificationCount()).toBe(0);
    });

    it('should respect per-category settings independently per channel', async () => {
      preferencesService.getOrCreatePreferences('user-0001');
      preferencesService.updatePreferences('user-0001', {
        email: { categories: { order_confirmation: false } },
        sms: { enabled: true, categories: { order_confirmation: true } },
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      // Email disabled for order_confirmation, but SMS enabled
      expect(emailAdapter.getSentEmails()).toHaveLength(0);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
    });

    it('should handle different users with different preferences', async () => {
      // user-0001: email only (default)
      preferencesService.getOrCreatePreferences('user-0001');

      // user-0002: all channels enabled
      preferencesService.getOrCreatePreferences('user-0002');
      preferencesService.updatePreferences('user-0002', {
        sms: { enabled: true },
        webhook: { enabled: true },
      });

      await eventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      await eventBus.emit(makeOrderCreatedEvent('user-0002', 'bob@example.com'));

      // user-0001: 1 email only
      // user-0002: 1 email + 1 SMS + 1 webhook = 3
      expect(notificationService.getNotificationCount()).toBe(4);
      expect(emailAdapter.getSentEmails()).toHaveLength(2);
      expect(smsAdapter.getSentMessages()).toHaveLength(1);
      expect(webhookAdapter.getDeliveries()).toHaveLength(1);
    });
  });

  describe('without preferences service', () => {
    it('should send all notifications when no preferences service is set', async () => {
      const freshEventBus = new EventBus();
      const freshNotifService = new NotificationService(freshEventBus);
      resetNotificationIdCounter();

      await freshEventBus.emit(makeOrderCreatedEvent('user-0001', 'alice@example.com'));
      expect(freshNotifService.getNotificationCount()).toBe(1);
    });
  });
});

